CREATE TABLE `backup_caipiao_touzhu_20261126` (
  `id` int(11) NOT NULL DEFAULT '0',
  `isdraw` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'Trạng thái: 0-chưa mở, 1-trúng, -1-không trúng, -2-hủy đơn',
  `trano` char(60) CHARACTER SET utf8 NOT NULL COMMENT 'Mã đơn hàng',
  `yjf` char(10) CHARACTER SET utf8 NOT NULL DEFAULT '1' COMMENT 'Đơn vị tiền tệ: 1-đồng, 0.1-hào, 0.01-xu, 0.001-ly',
  `typeid` char(20) CHARACTER SET utf8 NOT NULL COMMENT 'ID loại xổ số',
  `playid` char(30) CHARACTER SET utf8 NOT NULL COMMENT 'ID loại cược',
  `playtitle` varchar(60) CHARACTER SET utf8 NOT NULL COMMENT 'Tên loại cược',
  `cptitle` varchar(30) CHARACTER SET utf8 NOT NULL COMMENT 'Tiêu đề xổ số',
  `cpname` varchar(60) CHARACTER SET utf8 NOT NULL COMMENT 'Tên xổ số',
  `expect` char(25) CHARACTER SET utf8 NOT NULL COMMENT 'Mã kỳ quay',
  `uid` int(11) NOT NULL COMMENT 'ID hội viên',
  `username` char(60) CHARACTER SET utf8 NOT NULL COMMENT 'Tên hội viên',
  `itemcount` int(11) NOT NULL COMMENT 'Số lượng vé',
  `beishu` smallint(6) NOT NULL DEFAULT '1' COMMENT 'Tỷ lệ cược',
  `tzcode` longtext CHARACTER SET utf8 NOT NULL COMMENT 'Nội dung đặt cược',
  `repoint` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Tỷ lệ hoàn trả',
  `repointamout` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Số tiền hoàn trả',
  `mode` varchar(40) CHARACTER SET utf8 NOT NULL COMMENT 'Chế độ thưởng',
  `amount` decimal(20,2) NOT NULL COMMENT 'Số tiền cược',
  `amountbefor` decimal(14,2) NOT NULL COMMENT 'Số dư trước khi cược',
  `amountafter` decimal(14,2) NOT NULL COMMENT 'Số dư sau khi cược',
  `okamount` decimal(20,2) NOT NULL COMMENT 'Số tiền có thể thắng',
  `okcount` smallint(6) NOT NULL COMMENT 'Số lượng trúng thưởng',
  `Chase` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'Cược dây: 1-có, 0-không',
  `stopChase` tinyint(4) NOT NULL COMMENT 'Dừng cược dây khi trúng: 1-có, 0-không',
  `oddtime` int(11) NOT NULL COMMENT 'Thời gian đặt cược',
  `opencode` char(60) CHARACTER SET utf8 NOT NULL COMMENT 'Kết quả mở thưởng',
  `source` char(20) CHARACTER SET utf8 NOT NULL COMMENT 'Nguồn: pc, mobile',
  `play_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Loại chơi: 0-thường, 1-đặc biệt',
  `fenshu` int(11) NOT NULL DEFAULT '0' COMMENT 'Số phần cược nhóm',
  `ishemai` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Là cược nhóm: 1-có, 0-không',
  `rengou` int(11) NOT NULL DEFAULT '0' COMMENT 'Số phần tham gia cược nhóm',
  `isbaodi` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Có đảm bảo: 1-có, 0-không',
  `baodi` int(11) NOT NULL DEFAULT '0' COMMENT 'Số phần đảm bảo',
  `jindu` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Tiến độ cược nhóm',
  `hemaipic` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Hoa hồng cược nhóm',
  `isfull` int(11) NOT NULL DEFAULT '0' COMMENT 'Đã đủ phần: 1-đủ, 0-chưa đủ',
  `payamount` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số tiền tham gia cược nhóm',
  `bdjindu` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Tiến độ đảm bảo',
  `showtype` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'Loại hiển thị cược nhóm',
  `opentime` int(11) NOT NULL DEFAULT '0' COMMENT 'Thời gian mở thưởng',
  `realbaodi` int(11) NOT NULL DEFAULT '0' COMMENT 'Số phần đảm bảo thực tế',
  `winorno` int(6) NOT NULL DEFAULT '-1'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
